INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Содержание и методика современного дошкольного образования в деятельности воспитателя', 'soderzhanie-i-metodika-sovremennogo-doshkolnogo-obrazovaniya-v-deyatelnosti-vospitatelya', 'Для желающих всесторонне развивать детей дошкольного возраста.', 'Работник без профильного педагогического образования\nОсвоите необходимые знания и умения для работы с детьми в детском саду: от основ возрастной психологии до современных методов обучения и воспитания. После обучения вы получите официальный диплом, который позволит устроиться воспитателем в государственный или частный детский сад.\nСпециалист с педагогическим или специальным образованием (учителя, социальные педагоги, психологи, дефектологи)\nПолучите необходимые компетенции в области дошкольного образования, сможете переквалифицироваться и работать в должности воспитателя или заниматься профессиональным сопровождением образовательного процесса в ДОУ.\nНяня, ассистент, младший воспитатель\nПовысите уровень профессиональных компетенций и получите возможность заниматься не только присмотром и уходом за детьми в детском саду, но и осуществлять педагогическую деятельность в качестве воспитателя.', 'Дошкольное образование', 620, 'pp', 'заочная с применением дистанционных образовательных технологий', 27750, '[{"number": 1, "title": "Нормативно-правовая база в области дошкольного образования и воспитания"}, {"number": 2, "title": "Основы дошкольной педагогики"}, {"number": 3, "title": "Основы дошкольной психологии"}, {"number": 4, "title": "Планируемые результаты дошкольного образования"}, {"number": 5, "title": "Педагогическая деятельность по реализации программ дошкольного образования"}, {"number": 6, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 7, "title": "Планирование образовательной деятельности в условиях реализации образовательной программы дошкольного образования Итоговая аттестация"}, {"number": 8, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа воспитателем в государственном или частном детском саду: вы будете вести занятия по программам дошкольного образования, способствующие познавательному, речевому и художественно-эстетическому развитию детей, создавать развивающую предметно-пространственную среду, формировать у воспитанников основы культуры поведения и развивать из социальные навыки, а также взаимодействовать с родителями и коллегами.\\n\\nРабота педагогом в центрах творчества, детских клубах и студиях раннего развития: вы сможете проводить развивающие занятия для дошкольников (лепка, ритмика, логика), направленные на раскрытие их творческих и познавательных способностей, готовить детей к школе, организовывать праздники и конкурсы."], "abilities": []}', NULL, 1, @start_order + 1);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Менеджмент в сфере образования', 'menedzhment-v-sfere-obrazovaniya', 'Курс для тех, кто работает в сфере образования и хочет научиться грамотно управлять образовательной организацией, понимать цели и задачи менеджмента в образовании, успешно реализовывать лидерский потенциал, успешно управлять командой.', 'Руководитель\nПовысите уровень своих управленческих компетенций: изучите актуальные нормативные требования, современные подходы к администрированию и лучшие практики развития образовательных организаций.\nЗаместитель руководителя (завуч), методист, учитель\nПовысите профессиональный уровень в области управления образовательной организацией, включая кадровый менеджмент и стратегическое развитие. Приобретенные компетенции позволят претендовать на руководящую должность.', 'Дошкольное образование', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 29700, '[{"number": 1, "title": "Современная государственная политика Российской Федерации в сфере образования (по уровням образования)"}, {"number": 2, "title": "Формирование человеческого капитала современного общества как фактор воздействия на систему образования и управления образовательными организациями"}, {"number": 3, "title": "Образовательная организация как объект стратегического управления"}, {"number": 4, "title": "Организация финансово-экономической деятельности в образовательной организации"}, {"number": 5, "title": "Управленческие компетенции руководителя образовательной организации"}, {"number": 6, "title": "Личная эффективность руководителя"}, {"number": 7, "title": "Управление персоналом в образовательной организации"}, {"number": 8, "title": "Маркетинг в деятельности образовательной организации"}, {"number": 9, "title": "Управление качеством образования Итоговая аттестация"}, {"number": 10, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа руководителем, заместителем руководителя детского сада, школы или учреждения дополнительного образования: вы будете организовывать образовательный процесс, управлять коллективом педагогов и административным персоналом, осуществлять административное, финансовое и хозяйственное управление учреждением, планировать его развитие, обеспечивать безопасную и комфортную среду для обучения.\\n\\nРабота специалистом в организациях управления образования: вы сможете заниматься организационно-методической поддержкой образовательных учерждений, проводить мониторинг качества образования, координировать работу школ / детских садов, участвовать в разработке образовательных проектов и программ и внедрении новых образовательных технологий.\\n\\nВедение частной практики: опыт руководителя позволит вам разрабатывать и реализовывать образовательные проекты, консультировать руководителей и педагогические коллективы в частных школах, детских садах и образовательных центрах, разрабатывать стратегию развития учреждений, внедрять современные методики управления."], "abilities": []}', NULL, 1, @start_order + 2);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогика дополнительного образования', 'pedagogika-dopolnitelnogo-obrazovaniya', 'Вы станете дипломированным педагогом дополнительного образования, способным не только преподавать в рамках своего направления, но и разрабатывать авторские программы, управлять учебной группой и раскрывать таланты детей.', 'Специалист с профильным образованием без педагогической подготовки, который хочет работать в системе дополнительного образования\nИзучите специфику сферы дополнительного образования, научитесь создавать авторские программы,вести занятия в кружках,секциях, студиях, применять современные педагогические технологии в работе с детьми. Сможете официально работать в системе допобразования по своему профилю (искусство, спорт, техническое творчество и др.).\nШкольный учитель, воспитатель, социальный педагог, который хочет работать в системе дополнительного образования\nСможете официально работать в сфере допобразования (кружки, секции, центры развития), совмещая или меняя основную деятельность, с правом ведения занятий по выбранному направлению.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Государственная политика в сфере дополнительного образования детей. Состояние и перспективы развития дополнительного образования"}, {"number": 2, "title": "Основы общей педагогики"}, {"number": 3, "title": "Педагогическая психология"}, {"number": 4, "title": "Формирование здоровьесберегающей среды в учреждении дополнительного образования детей"}, {"number": 5, "title": "Педагогика дополнительного образования"}, {"number": 6, "title": "Организация деятельности педагога дополнительного образования детей"}, {"number": 7, "title": "Инклюзивные практики в дополнительном образовании"}, {"number": 8, "title": "Цифровые компетенции современного педагога дополнительного образования Итоговая аттестация"}, {"number": 9, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа педагогом дополнительного образования в школах, центрах детского и юношеского творчества, дворцах культуры: вы будете вести кружки и секции, руководить творческими и общественными детскими объединениями, создавать авторские программы и проекты, организовывать мероприятия, конкурсы и выставки.\\n\\nВедение частной практики: вы сможете открыть собственный образовательный проект, создать детский клуб или онлайн-школу, разрабатывать авторские образовательные программы, проводить мастер-классы, помогать детям и подросткам развивать навыки в выбранной области и в реализации творческих проектов."], "abilities": []}', NULL, 1, @start_order + 3);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Социальная педагогика', 'sotsialnaya-pedagogika', 'Для тех, кто желает работать в помогающей профессии, общаться с учащимися в школьных клубах и кружках, на мероприятиях социально-полезной направленности.', 'Специалист с профильным педагогическим / психологическим образованием без квалификации в области социальной педагогики\nПолучите право осуществлять социально-педагогическую деятельность в образовательных организациях в соответствии с профессиональным стандартом и требованиями ФГОС. Освоите базовые компетенции: сможете выявлять и поддерживать детей в трудной жизненной ситуации, взаимодействовать с семьёй и субъектами профилактики, применять современные технологии социально-педагогической поддержки.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 25800, '[{"number": 1, "title": "Педагогика как наука и область практической деятельности"}, {"number": 2, "title": "Психология как наука и область практической деятельности"}, {"number": 3, "title": "Организация и проведение социально-педагогического исследования с целью выявления социальных и личностных проблем детей всех возрастов"}, {"number": 4, "title": "Организация работы по социально-педагогической защиты прав ребенка"}, {"number": 5, "title": "Организация работы по обеспечению социально-педагогической поддержки семьи в формировании личности обучающегося"}, {"number": 6, "title": "Организация и проведение социально-педагогического консультирования"}, {"number": 7, "title": "Организация и осуществление социально-педагогической профилактики, коррекции и реабилитации участников образовательных отношений"}, {"number": 8, "title": "Основные функции деятельности социального педагога Итоговая аттестация"}, {"number": 9, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа социальным педагогом в общеобразовательной школе или детском саду: вы будете сопровождать детей группы риска, выявлять их социальные и психологические потребности, организовывать поддержку и профилактическую работу, помогать в адаптации, разрешении конфликтов и развитии навыков общения, взаимодействовать с родителями детей, находящихся в трудной жизненной ситуации, участвовать в организации мероприятий, направленных на формирование безопасной и поддерживающей образовательной среды.\\n\\nРабота специалистом по социальной работе в центрах помощи семье и детям: вы сможете разрабатывать индивидуальные программы реабилитации, защищать права несовершеннолетних, консультировать родителей по вопросам воспитания и адаптации, сопровождать семьи в трудных жизненных ситуациях, организовывать досуговую занятость воспитанников, взаимодействовать с органами опеки, образовательными учреждениями и социальными службами для обеспечения благополучия детей."], "abilities": []}', NULL, 1, @start_order + 4);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагог-психолог. Психолог в сфере образования', 'pedagog-psiholog-psiholog-v-sfere-obrazovaniya', 'Программа позволит работать с детьми и подростками, выстраивать процесс всестороннего развития, работать в смежных с психологией направлениях', 'Психолог, психолог-консультант\nУглубите свои зания в области педагогической психологии, сможете оказывать психологическую поддержку учащимся, родителям и коллегам, проводить диагностику, коррекцию и профилактику эмоциональных, поведенческих и учебных трудностей.\n\n\nУчитель, воспитатель, социальный педагог\nВы получите диплом педагога-психолога, дающий право работать в школах, детсадах и центрах. Научитесь решать типичные проблемы в образовательной среде: от адаптации и тревожности до профориентации и работы детьми с особыми образовательными потребностями.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 79350, '[{"number": 1, "title": "Нормативно-правовое обеспечение деятельности психолога образовательной организации"}, {"number": 2, "title": "Общепрофессиональные дисциплины"}, {"number": 3, "title": "Специальные дисциплины"}, {"number": 4, "title": "Практические инструменты педагога-психолога"}, {"number": 5, "title": "Практические приемы работы с эмоциональным выгоранием Итоговая аттестация"}, {"number": 6, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа педагогом-психологом в школе или детском саду: вы будете проводить психологическую диагностику учащихся, заниматься коррекцией эмоциональных и психологических проблем, организовывать групповые и индивидуальные занятия, реализовывать воспитательные и профилактические программы, организовывать профилактику буллинга, консультировать учащихся, родителей и педагогов.\\n\\nРабота в центре психолого-педагогической помощи: вы сможете оказывать поддержку детям и подросткам с ОВЗ и трудностями в обучении, разрабатывать и реализовывать индивидуальные программы поддержки, коррекции и развития, проводить реабилитационные мероприятия, консультировать родителей, взаимодействовать с комиссией по делам несовершеннолетних.\\n\\nВедение частной практики: ваши навыки будут применимы для проведения индивидуальных консультаций в детьми и их родителями, занятий по профориентации подростков, групповых занятий и тренингов, направленных на развитие навыков социализации, коммуникации и саморегуляции. Также в сферу вашей деятельности может входить диагностика готовности к школе, разработка авторских программ по развитию soft skills."], "abilities": []}', NULL, 1, @start_order + 5);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Начальное общее образование в условиях реализации ФГОС', 'pedagogicheskoe-obrazovanie-nachalnoe-obschee-obrazovanie-v-usloviyah-realizatsii-fgos', 'Программа профессиональной переподготовки для тех, кто хочет стать учителем начальных классов, способным реализовывать требования обновлённого ФГОС, применять современные педагогические технологии и создавать развивающую образовательную среду для младших школьников.', 'Специалист с педагогическим образованием (воспитатель, учитель основной школы)\nОсвоите методику обучения и воспитания младших школьников, требования ФГОС к содержанию и результатам обучения на уровне начального образования, сможете работать учителем начальных классов в государственной или частной школе.\n\n\nЗаместитель директора (завуч), методист\nИзучите специфику организации учебного процесса в начальных классах, требования ФГОС НОО, сможете осуществлять методическое сопровождение учителей начальных классов.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогика как наука и область практической деятельности. Общие основы педагогического процесса"}, {"number": 2, "title": "Воспитательный процесс"}, {"number": 3, "title": "Теория обучения (дидактика)"}, {"number": 4, "title": "Основная образовательная программа начального общего образования"}, {"number": 5, "title": "Воспитательная работа"}, {"number": 6, "title": "Структура и содержание урока в соответствии с требованиями ФГОС НОО"}, {"number": 7, "title": "Преподавание учебных предметов начальной школы в условиях реализации ФГОС"}, {"number": 8, "title": "Система оценки достижения планируемых результатов освоения основной образовательной программы НОО"}, {"number": 9, "title": "Формирование и оценка личностных и метапредметных результатов в соответствии с требованиями обновленного ФГОС НОО"}, {"number": 10, "title": "Формирование и оценка предметных результатов в соответствии с требованиями обновленного ФГОС НОО"}, {"number": 11, "title": "Нормативно-правовые аспекты обучения детей с ограниченными возможностями здоровья"}, {"number": 12, "title": "Обязательные требования при реализации федеральной адаптированной образовательной программы"}, {"number": 13, "title": "Цифровые компетенции современного педагога Итоговая аттестация"}, {"number": 14, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем начальных классов в школе: вы будете проводить уроки по основным предметам (русский язык, литературное чтение, математика, окружающий мир), развивать у детей навыки чтения, письма, счёта, логического и творческого мышления, формировать познавательный интерес и любовь к обучению. Также вы будете заниматься методической работой, организацией внеурочной деятельности, поддержкой эффективного взаимодействия с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: вы сможете создавать и реализовывать авторские программы обучения, проводить развивающие занятия по логике, творчеству или soft skills, готовить детей к школе в дошкольных группах, организовывать детские образовательные лагеря и мероприятия.\\n\\nЧастная практика (репетиторство): вы будете проводить индивидуальные занятия с детьми младшего школьного возраста, помогать им преодолевать трудности в обучении и развивать базовые учебные навыки, готовить к ВПР, олимпиадам и интеллектуальным конкурсам."], "abilities": []}', NULL, 1, @start_order + 6);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. История и обществознание в условиях реализации ФГОС ООО, СОО', 'pedagogicheskoe-obrazovanie-istoriya-i-obschestvoznanie-v-usloviyah-realizatsii-fgos-ooo-soo', 'Программа для учителей истории и обществознания научит грамотно планировать и проводить учебные занятия, разрабатывать рабочую программу по предмету, а также применять современные образовательные технологии.', 'Специалист с профильным историческим / гуманитарным образованием без педагогической подготовки\nПолучите право преподавать историю и обществознание в 5–11 классах в соответствии с требованиями ФГОС ООО и СОО. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательные технологии и методы оценки знаний учащихся.\n\nУчитель смежных дисциплин, желающий преподавать историю и обществознание в школе\nСможете вести историю и обществознание как второй предмет, применять междисциплинарный подход, связывая их с другими гуманитарными и социальными дисциплинами (литература, право, экономика, география), использовать современные образовательные технологии на уроках в условиях реализации ФГОС.\n\nРепетитор\nИзучите требования ФГОС ООО и СОО и содержание школьной программы по истории и обществознанию, освоите современные педагогические технологии и методические инструменты для работы с учениками основной и старшей школы.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 25800, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация ФГОС ООО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация ФГОС среднего общего образования в общеобразовательных организациях"}, {"number": 4, "title": "Содержание и организация обучения инстории и обществознанию в условиях реализации ФГОС Итоговая аттестация"}, {"number": 5, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем истории и обществознания в школе: вы будете вести уроки, организовывать внеурочные занятия (например, исторические клубы, тематические дебаты, викторины и конкурсы), участвовать в методической деятельности — разрабатывать программы и методики, участвовать в педсоветах, взаимодейстовать с родителями и коллегами.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: ваши навыки будут применимы для создания авторских программ по истории и обществознанию, ведения кружков по своему профилю, помощи учащимся в углубленном изучении предметов.\\n\\nЧастная практика (репетиторство): вы сможете готовить учеников к итоговой аттестации (ВПР, ОГЭ, ЕГЭ) и олимпиадам, помогать с разбором сложных тем, развитием аналитических навыков — с индивидуальным подходом к каждому. Также для вас открывается возможность участия в разработке образовательного контента и учебных материалов для онлайн-платформ, создание программ для музеев и исторических парков."], "abilities": []}', NULL, 1, @start_order + 7);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Логопедия. Работа с обучающимися с нарушениями речи и коммуникации', 'logopediya-rabota-s-obuchayuschimisya-s-narusheniyami-rechi-i-kommunikatsii', 'Для тех, кто желает работать с детьми с разными речевыми нарушениями, а также помогать детям с ОВЗ дошкольного возраста.', 'Воспитатель, учитель\nПолучите квалификацию логопеда с правом работы в детских садах и центрах развития, научитесь выявлять и корректировать речевые нарушения у детей 2-7 лет, сможете проводить раннюю диагностику и составлять коррекционные программы для детей раннего и дошкольного возраста, которые имеют нарушения развития или риск их возникновения.\n\n\nСпециалист с медицинским образованием\nПолучите официальную квалификацию логопеда с правом работы в образовательных и медицинских учреждениях, сможете сочетать медицинские знания с логопедическими методиками в работе с детьми с ОВЗ раннего и дошкольного возраста.', 'Дошкольное образование', 1300, 'pp', 'заочная с применением дистанционных образовательных технологий', 62900, '[{"number": 1, "title": "Нормативно-правовые аспекты обучения детей с ограниченными возможностями здоровья"}, {"number": 2, "title": "Медико-биологические основы дефектологии и логопедии"}, {"number": 3, "title": "Психология развития и возрастная психология"}, {"number": 4, "title": "Специальная педагогика и психология"}, {"number": 5, "title": "Инклюзивное и интегрированное образование"}, {"number": 6, "title": "Логопедическая работа по диагностике, коррекции и профилактике"}, {"number": 7, "title": "Дислалия"}, {"number": 8, "title": "Ринолалия"}, {"number": 9, "title": "Дизартрия"}, {"number": 10, "title": "Алалия"}, {"number": 11, "title": "Афазия"}, {"number": 12, "title": "Заикание"}, {"number": 13, "title": "Нарушения письменной речи"}, {"number": 14, "title": "Традиционные логопедические технологии"}, {"number": 15, "title": "Основные направления исследований современной дефектологии: диагностика, профилактика, коррекция. Особенности организации инклюзивного обучения в образовательных организациях"}, {"number": 16, "title": "Основы олигофренопедагогики"}, {"number": 17, "title": "Основы тифлопедагогики"}, {"number": 18, "title": "Основы сурдопедагогики"}, {"number": 19, "title": "Педагогика и психология детей с РАС"}, {"number": 20, "title": "Педагогика и психология детей с НОДА"}, {"number": 21, "title": "Современные образовательные технологии в работе с детьми с ОВЗ"}, {"number": 22, "title": "Психолого-педагогическое сопровождение ребенка с ОВЗ В ДОО Итоговая аттестация"}, {"number": 23, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа логопедом в центрах раннего развития: вы будете проводить скрининг речевого развития детей 0-3 лет и коррекцию при нарушении речевых функций — преодоление задержки речевого развития, формирование правильного звукопроизношения. Также в сферу вашей деятельности входит обучение родителей техникам стимуляции и развития речи.\\n\\nРабота логопедом/дефектологом в государственном или частном детском саду: вы сможете проводить комплексную диагностику детей с ОВЗ, разрабатывать индивидуальные коррекционные маршруты, вести как индивидуальные, так и групповые занятия, направленные на коррекцию речи и развитие коммуникативных навыков детей, помогая им успешнее адаптироваться в коллективе и подготовиться к обучению в школе.\\n\\nВедение частной практики (логопедический кабинет/онлайн): специалист может самостоятельно организовать работу с детьми раннего и дошкольного возраста, проводить диагностику и индивидуальную коррекцию в удобной форме — очно или дистанционно через цифровые платформы. Частная практика позволяет создавать и использовать авторские методики и образовательный контент для родителей, гибко планировать график и оказывать помощь семьям, которым необходима индивидуальная поддержка в развитии речи ребёнка"], "abilities": []}', NULL, 1, @start_order + 8);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Труд (технология) в условиях реализации ФГОС', 'pedagogicheskoe-obrazovanie-trud-tehnologiya-v-usloviyah-realizatsii-fgos', 'Программа предназначена для слушателей, желающих грамотно планировать и проводить учебные занятия, разрабатывать рабочую программу по предмету, а также применять современные образовательные технологии.', 'Специалист с профильным образованием без педагогической подготовки\nИзучите основы педагогики и психологии, получите право преподавать технологию в школе, сможет готовить учеников к современным технологическим профессиям.\n\n\nСпециалист с педагогическим образованием (учитель, педагог дополнительного образования)\nПолучите дополнительную квалификацию учителя труда (технологии), сможете обучать школьников техническому творчеству, ручному труду, разработке и реализации творческих проектов.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация обновленного ФГОС НОО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация обновленного ФГОС НОО в общеобразовательных организациях"}, {"number": 4, "title": "Содержание и организация обучения \\"Труду (технологии)\\" в условиях реализации ФГОС НОО"}, {"number": 5, "title": "Содержание и организация обучения \\"Труду (технологии)\\" в условиях реализации ФГОС НОО Итоговая аттестация"}, {"number": 6, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем труда (технологии) в школе: вы будете проводить уроки и практические занятия, обучать основам работы с инструментами и материалами, развивать у учеников творческие навыки, формировать умение работать в команде, готовить методические материалы, участвовать в школьных мероприятиях, налаживать продуктивное взаимодействие с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: вы сможете создавать авторские программы в области прикладного творчества, вести кружки по различным праправлениям (столярному, слесарному, швейному делу, 3D-моделированию, робототехнике), готовить учеников к соревнованиям, выставкам и помогать им в реализации творческих проектов."], "abilities": []}', NULL, 1, @start_order + 9);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Иностранный язык в условиях реализации ФГОС ООО, СОО', 'pedagogicheskoe-obrazovanie-inostrannyy-yazyk-v-usloviyah-realizatsii-fgos-ooo-soo', 'Программа для тех, кто хочет научиться применять лучшие методики обучения иностранным языкам и современным образовательным технологиям.', 'Специалист с филологическим образованием без педагогической подготовки\nСпециалист с профильным лингвистическим/филологическим образованием без педагогической подготовки. Получите право преподавать английский язык в 5-11 классах в соответствии с требованиями ФГОС ООО и СОО. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательные технологии и методы оценки знаний учащихся по иностранному языку.\n\nУчитель смежных дисциплин, желающий преподавать английский язык в школе\nСможете вести английский как второй предмет, применять междисциплинарный подход, связывая иностранный язык с другими предметными областями (литература, история, обществознание), использовать современные образовательные технологии на уроках в условиях реализации ФГОС.\n\nРепетитор\nИзучите требования ФГОС ООО и СОО и содержание школьной программы по английскому языку, освоите современные педагогические технологии и методические инструменты для работы с учениками основной и старшей школы.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация обновленного ФГОС ООО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация обновленного ФГОС среднего общего образования в общеобразовательных организациях"}, {"number": 4, "title": "Иностранный язык в условиях реализации ФГОС Вариативный модуль: английский или немецкий язык Итоговая аттестация"}, {"number": 5, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем иностранного языка в школе: вы будете проводить уроки и дополнительные занятия (например, в школьных разговорных клубах), развивать у учеников навыки говорения и понимания речи, чтения и письма на иностранном языке, заниматься методической работой, участвовать в школьных проектах, поддерживать эффективное взаимодействие с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: вы сможете разрабатывать и внедрять собственные программы и курсы, вести профильные кружки и клубы, организовывать языковые лагеря.\\n\\nЧастная практика (репетиторство): индивидуальная работа по поготовке к итоговым аттестациям (ВПР, ОГЭ, ЕГЭ) и олимпиадам, помощь в углубленном изучении иностранного языка, консультирование по устным и письменным заданиям. Также вы сможете развиваться в области разработки образовательного контента и учебных материалов для онлайн-платформ."], "abilities": []}', NULL, 1, @start_order + 10);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Тьютор в образовательной организации', 'tyutor-v-obrazovatelnoy-organizatsii', 'Программа для тех, кто хочет найти индивидуальный подход к ученикам, выявить их особенности, интересы и способности.', 'Специалист с педагогическим образованием (учитель, воспитатель и др.)\nОсвоите набирающую популярность профессию, изучите технологии индивидуализированного и персонализированного образования, сможете выстраивать индивидуальные траектории развития для школьников и студентов, вести профориентационную работу.\n\n\nЗаместитель директора (завуч), методист\nИзучите основные принципы персонализированного и индивидуализированного образования, получите компетенции для внедрения тьюторской модели в школе.\n\n\nРепетитор\nПолучите квалификацию тьютора, сможете не только закрывать пробелы по предмету, но и комплексно сопровождать личностное развитие своих учеников, быть наставником, профориентологом.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 31800, '[{"number": 1, "title": "Основы возрастной анатомии и физиологии"}, {"number": 2, "title": "Основы возрастной педагогики и психологии"}, {"number": 3, "title": "Понятие, сущность и история возникновения тьюторства"}, {"number": 4, "title": "Роль тьюторства в образовательном процессе общеобразовательной организации"}, {"number": 5, "title": "Технологии тьюторского сопровождения интереса обучающихся школы в рамках реализации ФГОС"}, {"number": 6, "title": "Особенности тьюторского сопровождения различных категорий обучающихся"}, {"number": 7, "title": "Тьюторское сопровождение как механизм навигации в профессиональном самоопределение подростков"}, {"number": 8, "title": "Этапы и инструменты в работе тьютора при сопровождении в профессиональном самоопределении подростков"}, {"number": 9, "title": "Разбор кейсов по профессиональной навигации школьников Итоговая аттестация"}, {"number": 10, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа тьютором в школе, колледже, вузе: вы будете помогать школьникам и студентам выстраивать индивидуальные образовательные траектории и карьерные планы, сопровождать их проектно-исследовательскую деятельность, а также создавать комфортную среду для детей с ОВЗ — адаптировать программы, поддерживать во время интеграции в коллективе.\\n\\nЧастная практика: ваши навыки будут применимы в коучинге и наставничестве, консультировании семей по образовательным вопросам, сопровождении одарённых детей, а также в корпоративном обучении (сопровождение новых сотрудников, карьерное консультирование).\\n\\nЭкспертная деятельность: тьюторы разрабатывают образовательные методики, обучают коллег, выступают на конференциях. Опытный тьютор — востребованный специалист в сфере EdTech-проектов.\\n\\nКарьерные горизонты: вы сможете работать непосредственно с учащимися, координировать тьюторскую службу в организации, развивать это направление как методист или руководитель."], "abilities": []}', NULL, 1, @start_order + 11);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Методист образовательной организации', 'pedagogicheskoe-obrazovanie-metodist-obrazovatelnoy-organizatsii', 'Программа для тех, кто хочет научиться грамотно проектировать образовательный процесс, осуществлять методическое сопровождение в образовательных организациях различного типа.', 'Специалист с профильным педагогическим образованием без опыта методической работы\nПолучите право осуществлять методическую деятельность в образовательной организации в соответствии с профессиональным стандартом и требованиями ФГОС. Освоите базовые методические компетенции: сможете разрабатывать учебно-методическую документацию, анализировать образовательные программы, оказывать методическую помощь педагогам, применять современные подходы к оценке качества образования.\n\nУчитель-предметник, желающий перейти на методическую работу в образовательной организации\nСможете работать методистом как новое профессиональное направление, применяя практический опыт преподавания для разработки эффективных методических решений. Освоите междисциплинарный подход, связывая методическую работу с педагогикой, психологией, управлением образованием и нормативно-правовым регулированием, использовать современные образовательные технологии при проектировании учебного процесса.', 'Дошкольное образование', 250, 'pp', 'заочная с применением дистанционных образовательных технологий', 18150, '[{"number": 1, "title": "Педагогика как наука и область практической деятельности. Общие основы педагогического процесса"}, {"number": 2, "title": "Воспитательный процесс. Особенности содержания и организации воспитательного процесса на современном этапе"}, {"number": 3, "title": "Теория обучения (дидактика). Особенности содержания и организации дидактического процесса на современном этапе"}, {"number": 4, "title": "Методическая деятельность в образовательном учреждении – роль, значение, правовые основы"}, {"number": 5, "title": "Специфика методического обеспечения образовательного процесса в общеобразовательной организации"}, {"number": 6, "title": "Особенности организации методической работы в образовательных организациях разных типов Итоговая аттестация"}, {"number": 7, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа методистом в общеобразовательной школе: вы будете разрабатывать, корректировать и внедрять учебные программы в соответствии с ФГОС и ФООП, организовывать методические советы и курсы повышения квалификации, сопровождать реализацию образовательных стандартов и внедрение педагогических технологий, помогать учителям в планировании уроков и внеклассных мероприятий, анализировать эффективность учебного процесса.\\n\\nРабота методистом в управлении образования: ваши навыки будут востребованы для координации работы методических служб района/городы, внедрения инновационных образовательных технологий, проведения мониторинга качества образования, организации конкурсов профессионального мастерства, конференций и обменов опытом.\\n\\nРабота методистом в учреждении дополнительного образования: вы сможете создавать авторские образовательные программы и методические пособия, проводить семинары по актуальным педагогическим практикам, а также будете проводить мониторинг качества дополнительных образовательных услуг."], "abilities": []}', NULL, 1, @start_order + 12);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Математика в условиях введения и реализации ФГОС ООО, СОО', 'pedagogicheskoe-obrazovanie-matematika-v-usloviyah-vvedeniya-i-realizatsii-fgos-ooo-soo', 'Программа для лиц, которые планируют стать учителями математики, способными реализовывать требования федеральных государственных образовательных стандартов, использовать современные педагогические технологии и обеспечивать высокий уровень образовательного процесса.', 'Специалист с профильным математическим/инженерным образованием без педагогической подготовки\nПолучите право преподавать математику в 5-11 классах в соответствии с требованиями ФГОС. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательных технологий и методы оценки знаний учащихся.\n\n\nУчитель смежных дисциплин, желающий преподавать математику в школе\nСможете вести математику как второй предмет, применять междисциплинарный подход, связывая математику с другими естественнонаучными дисциплинами, использовать современные образовательные технологии на уроках.\n\n\nРепетитор\nИзучите требования ФГОС и содержание школьной программы по матемтаике, освоите современные педагогические технологии и методические инструменты для работы с учениками основной и старшей школы.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация ФГОС ООО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация обновленного ФГОС СОО в общеобразовательных организациях"}, {"number": 5, "title": "Преподавание математики в соответствии с обновленным ФГОС Итоговая аттестация"}, {"number": 5, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем математики в школе: вы будете вести уроки, планировать и проводить дополнительные занятия, направленные на развитие логики, внимательности и умения работать с информацией, помогать ученикам раскрывать свой потенциал, разрабатывать методические материалы, участвовать в олимпиадах и школьных проектах, поддерживать продуктивное общение с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: ваши знания и опыт пригодятся для создания авторских курсов, ведения математических кружков, подготовки к предметным конкурсам и турнирам, участия в проектной и исследовательской деятельности.\\n\\nЧастная практика (репетиторство): вы сможете готовить учеников к итоговой аттестации (ВПР, ОГЭ, ЕГЭ) и олимпиадам, помогать в разборе сложных тем, сопровождать проектные работы, консультировать по углублённым разделам математики и смежных дисциплин."], "abilities": []}', NULL, 1, @start_order + 13);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. География в условиях реализации ФГОС ООО, СОО', 'pedagogicheskoe-obrazovanie-geografiya-v-usloviyah-realizatsii-fgos-ooo-soo', 'Программа для тех, кто желает увлекать школьников культурой разных народов мира, помогать понять ученикам, как устроена наша планета, учить правильно читать географические карты.', 'Специалист с профильным географическим / естественнонаучным образованием без педагогической подготовки\nПолучите право преподавать географию в 5–11 классах в соответствии с требованиями ФГОС ООО и СОО. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательные технологии и методы оценки знаний учащихся.\n\nУчитель смежных дисциплин, желающий преподавать географию в школе\nСможете вести географию как второй предмет, применять междисциплинарный подход, связывая географию с другими естественнонаучными и общественными дисциплинами (биология, экология, история, экономика), использовать современные образовательные технологии на уроках в условиях реализации ФГОС.\n\nРепетитор\nИзучите требования ФГОС ООО и СОО и содержание школьной программы по географии, освоите современные педагогические технологии и методические инструменты для работы с учениками основной и старшей школы.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация обновленного ФГОС ООО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация обновленного ФГОС среднего общего образования в общеобразовательных организациях"}, {"number": 4, "title": "Огранизация процесса обучения географии в условиях реализации обновленного ФГОС Итоговая аттестация"}, {"number": 5, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем географии в школе: вы будете проводить уроки, организовывать дополнительные занятия и исследовательские проекты, развивать у школьников умение анализировать природные и социальные процессы, формировать экологическое мышление, вести методическую работу, участвовать в школьных мероприятиях, налаживать сотрудничество с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: ваши навыки будут востребованы для разработки авторских программ, ведения географических кружков, туристических секций, исследовательских лабораторий.\\n\\nЧастная практика (репетиторство): вы сможете готовить учеников к итоговой аттестации (ВПР, ОГЭ, ЕГЭ) и олимпиадам по географии, будете помогать им в изучении сложных тем, сопровождать проектные и исследовательские работы."], "abilities": []}', NULL, 1, @start_order + 14);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Русский язык и литература в условиях реализации ФГОС ООО, СОО', 'pedagogicheskoe-obrazovanie-russkiy-yazyk-i-literatura-v-usloviyah-realizatsii-fgos-ooo-soo', 'Программа для учителей русского языка и литературы научит грамотно планировать и проводить учебные занятия, разрабатывать рабочую программу по предмету, а также применять современные образовательные технологии.', 'Специалист с профильным филологическим / гуманитарным образованием без педагогической подготовки\nПолучите право преподавать русский язык и литературу в 5–11 классах в соответствии с требованиями ФГОС ООО и СОО. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательные технологии и методы оценки знаний учащихся.\n\nУчитель смежных дисциплин, желающий преподавать русский язык и литературу в школе\nСможете вести русский язык и литературу как второй предмет, применять междисциплинарный подход, связывая их с другими гуманитарными дисциплинами (история, обществознание, мировая художественная культура), использовать современные образовательные технологии на уроках в условиях реализации ФГОС.\n\nРепетитор\nИзучите требования ФГОС ООО и СОО и содержание школьной программы по русскому языку и литературе, освоите современные педагогические технологии и методические инструменты для работы с учениками основной и старшей школы.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 25800, '[{"number": 1, "title": "Педагогика как наука и область практической деятельности. Общие основы педагогического процесса"}, {"number": 2, "title": "Воспитательный процесс. Особенности содержания и организации воспитательного процесса на современном этапе"}, {"number": 3, "title": "Теория обучения (дидактика). Особенности содержания и организации дидактического процесса на современном этапе"}, {"number": 4, "title": "Обновленный Федеральный государственный образовательный стандарт основного общего образования"}, {"number": 5, "title": "Основная образовательная программа основного общего образования"}, {"number": 6, "title": "Система оценки достижения планируемых результатов освоения основной образовательной программы ООО"}, {"number": 7, "title": "Формирование и оценка личностных результатов в соответствии с требованиями обновленного ФГОС ООО"}, {"number": 8, "title": "Формирование и оценка метапредметных результатов в соответствии с требованиями обновленного ФГОС ООО"}, {"number": 9, "title": "Обновленный Федеральный государственный образовательный стандарт среднего общего образования"}, {"number": 10, "title": "Основная образовательная программа среднего общего образования"}, {"number": 11, "title": "Оценка качества освоения основной образовательной программы среднего общего образования"}, {"number": 12, "title": "Формирование и оценка личностных результатов в соответствии с требованиями обновленного ФГОС"}, {"number": 13, "title": "Формирование и оценка метапредметных результатов в соответствии с требованиями обновленного ФГОС"}, {"number": 14, "title": "Формирование и оценка предметных результатов в соответствии с требованиями ФГОС ООО"}, {"number": 15, "title": "Конструирование современного урока литературы в условиях введения обновленных ФГОС"}, {"number": 16, "title": "Мир русской литературы ХIХ-ХХI вв."}, {"number": 17, "title": "Методика и специфика обучения предмету «Русская родная литература»"}, {"number": 18, "title": "Моделирование и конструирование современного урока русского языка"}, {"number": 19, "title": "Формирование предметных компетенций при обучении русскому языку в соответствии с требованиями ФГОС ООО"}, {"number": 20, "title": "Методика и специфика обучения предмету «Русский родной язык» Итоговая аттестация"}, {"number": 21, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем русского языка и литературы в школе: в сферу вашей деятельности входит ведение уроков и внеурочной деятельности (литературные клубы, театральные студии), воспитательная работа — развитие речи, культуры общения, патриотическое и эстетическое воспитание; методическая деятельность — разработка программ, участие в педсоветах, конкурсах; взаимодействие с родителями и коллегами.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: создание авторских курсов по подготовке к олимпиадам, конкурсам, ведение кружков (риторика, журналистика, литературное творчество).\\n\\nЧастная практика (репетиторство): вы будете готовить учеников к итоговой аттестации (ВПР, ОГЭ, ЕГЭ) и олимпиадам, помогать в углубленном изучении предмета и разборе сложных тем — с индивидуальным подходом к каждому."], "abilities": []}', NULL, 1, @start_order + 15);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическое образование. Музыка в условиях реализации ФГОС', 'pedagogicheskoe-obrazovanie-muzyka-v-usloviyah-realizatsii-fgos', 'Программа предназначена для слушателей, желающих привить школьникам высокое искусство в музыкальной сфере', 'Специалист с профильным музыкальным / творческим образованием без педагогической подготовки\nПолучите право преподавать музыку в школе в соответствии с требованиями ФГОС. Освоите базовые методические компетенции: сможете разрабатывать и проводить уроки, применять современные образовательные технологии и методы оценки знаний учащихся.\n\nПедагог дополнительного образования\nСможете вести музыкальные кружки, студии, факультативы и творческие объединения в системе дополнительного образования детей. Освоите методики разработки дополнительных общеразвивающих программ, организации внеурочной деятельности и массовых музыкальных мероприятий с учётом требований ФГОС.', 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Педагогические технологии в современной школе"}, {"number": 2, "title": "Введение и реализация обновленного ФГОС НОО в общеобразовательных организациях"}, {"number": 3, "title": "Введение и реализация обновленного ФГОС ООО в общеобразовательных организациях"}, {"number": 4, "title": "Содержание и организация обучения предмета «Музыка» в условиях реализации ФГОС Итоговая аттестация"}, {"number": 5, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа учителем музыки в школе: вы будете проводить уроки и творческие занятия, развивать у учеников музыкальный слух, чувство ритма и вокальные навыки, знакомить с музыкальной культурой и её историей. В сферу вашей деятельности также будет входить подготовка методических материалов, участие в школьных культурных проектах, выстраивание эффективной коммуникации с родителями, коллегами и администрацией.\\n\\nРабота в государственных и частных учреждениях дополнительного образования: вы сможете вести занятия в музыкальных кружках и студиях, руководить творческими объединениями, готовить участников к музыкальным конкурсам, концертам и творческим фестивалям.\\n\\nВедение частной практики: для вас открыта возможность вести индивидуальные занятия по музыке (вокал или игра на музыкальных инструментах), помогать в подготовке к выступлениям, конкурсным прослушиваниям и экзаменам для поступления в музыкальные учебные заведения."], "abilities": []}', NULL, 1, @start_order + 16);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Дефектология. Работа с обучающимися с умственной отсталостью (интеллектуальными нарушениями), с тяжелыми и множественными нарушениями развития', 'defektologiya-rabota-s-obuchayuschimisya-s-umstvennoy-otstalostyu-intellektualnymi-narusheniyami-s-tyazhelymi-i-mnozhestvennymi-narusheniyami-razvitiya', 'Для тех, кто работает с разными категориями лиц, имеющих задержку психического развития и нарушения интеллекта.', 'Специалист с высшим  педагогическим / психологическим образованием без квалификации в области работы в олигофренопедагогике\nПолучите право осуществлять коррекционно-педагогическую деятельность с обучающимися, имеющими интеллектуальные нарушения, тяжелые и множественные нарушения развития, в соответствии с требованиями ФГОС. Освоите базовые компетенции: сможете разрабатывать и реализовывать адаптированные основные общеобразовательные программы, применять специальные методики и технологии коррекционной работы, осуществлять психолого-педагогическую диагностику и оценку результатов обучения.', 'Специальное образование', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23600, '[{"number": 1, "title": "Специальная педагогика и психология"}, {"number": 2, "title": "Психолого-педагогическая диагностика умственной отсталости"}, {"number": 3, "title": "Современные воспитательные системы в работе с детьми с умственной отсталостью"}, {"number": 4, "title": "Инклюзивное образование в РФ"}, {"number": 5, "title": "Разработка и реализация АООП/АОП для умственно отсталых детей"}, {"number": 6, "title": "Разработка и реализация СИПР"}, {"number": 7, "title": "Методики преподавания дисциплин"}, {"number": 8, "title": "Профессиональный стандарт «Учитель-дефектолог» (проект)"}, {"number": 9, "title": "Инновации в специальном образовании"}, {"number": 10, "title": "Невропатология"}, {"number": 11, "title": "Информационные компьютерные технологии в обучении детей с нарушениями интеллекта, ЗПР"}, {"number": 12, "title": "Сопровождение ребенка с уо, ЗПР и его семьи Итоговая аттестация"}, {"number": 13, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа дефектологом в общеобразовательной или коррекционной школе: вы будете проводить коррекционные занятия по адаптированным программам, разрабатывать и внедрять индивидуальные маршруты для учеников с нарушениями интеллекта, направленные на развитие познавательных, речевых и социально-бытовых навыков. В сферу вашей деятельности также будет входить взаимодействие с учителями и родителями для обеспечения эффективного обучения и социальной интеграции учащихся.\\n\\nРабота дефектологом в центре психолого-медико-педагогического сопровождения: вы сможете проводить комплексную диагностику детей с интеллектуальными нарушениями, разрабатывать индивидуальные программы коррекции и развития, составлять рекомендации для образовательных учреждений, а также консультировать родителей и педагогов, обеспечивая комплексный подход к обучению и социальной адаптации детей.\\n\\nВедение частной практики: учитель-дефектолог может разрабатывать авторские методики коррекционной работы, проводить индивидуальные занятия, готовить к школе детей с ОВЗ и консультировать их родителей. Частная практика позволяет гибко планировать график работы, применять индивидуальный подход и оказывать адресную поддержку в развитии навыков и социальной адаптации ребёнка."], "abilities": []}', NULL, 1, @start_order + 17);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Специалист по пожарной профилактике', 'spetsialist-po-pozharnoy-profilaktike', 'Программа для тех, кто хочет освоить востребованную на рынке труда профессию и стать специалистом в сфере пожарной безопасности.', 'Руководитель и его заместители\nСможете оценить состояние пожарной безопасности в своей организации, разработать необходимые документы, организовать обучение работников.\n\n\nОтветственный за пожарную безопасность без профильного образования\nПолучите уровень компетенций, позволяющий обеспечивать пожарную безопасность на вашем предприятии.', 'Безопасность', 256, 'pp', 'заочная с применением дистанционных образовательных технологий', 9800, '[{"number": 1, "title": "Пожары. Классификация пожаров. Опасные факторы пожаров"}, {"number": 2, "title": "Организационные основы обеспечения пожарной безопасности в Российской Федерации"}, {"number": 3, "title": "Требования пожарной безопасности к объектам защиты организаций"}, {"number": 4, "title": "Система обеспечения пожарной безопасности объектов защиты"}, {"number": 5, "title": "Требования пожарной безопасности при проектировании, строительстве и эксплуатации объекта защиты"}, {"number": 6, "title": "Тушение пожаров и оказание первой помощи пострадавшим"}, {"number": 7, "title": "Практические задания Итоговая аттестация"}, {"number": 8, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа специалистом по пожарной безопасности в любой организации (на производстве, в бизнес-центрах, ТЦ, медицинских или образовательных учреждения и т.п.): в сферу вашей деятельности входит проведение инструктажей, профилактических мероприятий и проверок, обучение сотрудников, ведение документации и отслеживание соблюдений норм пожарной безопасности.\\n\\nРуководство службы пожарной безопасности в компаниях, организациях ЖКХ, образовательных или медицинских учреждениях: вы будете управлять противопожарными системами и персоналом, организовывать взаимодействие с контролирующими организациями.\\n\\nРабота независимым экспертом в частных аудиторских компаниях: вы сможете организовывать проверки объектов и давать рекомендации по пожарной безопасности, проводить консультации по приведению зданий в соответствие с требованиями."], "abilities": []}', NULL, 1, @start_order + 18);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогическая деятельность советника директора по воспитанию и взаимодействию с детскими общественными объединениями в образовательной организации', 'pedagogicheskaya-deyatelnost-sovetnika-direktora-po-vospitaniyu-i-vzaimodeystviyu-s-detskimi-obschestvennymi-obedineniyami-v-obrazovatelnoy-organizatsii', 'После прохождения курса вы станете специалистом, который не просто организует мероприятия, а проектирует среду доверия и соучастия, выступает наставником для детских инициатив и связующим звеном между учениками, педагогами и родителями.', 'Педагоги\nКурс для педагогов, которые устали от формальных мероприятий «для галочки» и хотят научиться выстраивать системную воспитательную работу, находить общий язык с современными детьми и их родителями, а также освоить инструменты проектного управления, чтобы превратить школу в пространство реальных возможностей и детских инициатив.', 'Дошкольное образование', 340, 'pp', 'заочная с применением дистанционных образовательных технологий', 15700, '[{"number": 1, "title": "Нормативно-правовые основы воспитания. Роль советника"}, {"number": 2, "title": "Психолого-педагогические особенности работы с учащимися"}, {"number": 3, "title": "Детские общественные объединения и ученическое самоуправление"}, {"number": 4, "title": "Проектирование и организация событийной воспитательной деятельности"}, {"number": 5, "title": "Партнерство в воспитательной работе: взаимодействие с педагогическим коллективом и родителями"}, {"number": 6, "title": "Цифровые инструменты и медиаграмотность в деятельности советника директора по воспитанию и взаимодействию с детскими общественными объединениями Итоговая аттестация"}, {"number": 7, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["По итогам обучения вы сможете разрабатывать и внедрять программы воспитания, основанные на реальных запросах детей, выстраивать эффективное партнерство с детскими общественными объединениями, сопровождать проектные и конкурсные инициативы школьников от идеи до победы, а также создавать в школе атмосферу, в которой каждому ребенку интересно и безопасно развиваться."], "abilities": []}', NULL, 1, @start_order + 19);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Музыкальное образование в дошкольной образовательной организации в условиях реализации ФГОС дошкольного образования', 'muzykalnoe-obrazovanie-v-doshkolnoy-obrazovatelnoy-organizatsii-v-usloviyah-realizatsii-fgos-doshkolnogo-obrazovaniya', 'Курс для тех, кто формирует у дошкольников музыкальный вкус, сопровождает процесс воспитания и обучения музыкальным сопровождением.', NULL, 'Дошкольное образование', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Федеральный государственный образовательный стандарт дошкольного образования"}, {"number": 2, "title": "Основы дошкольной педагогики"}, {"number": 3, "title": "Планируемые результаты дошкольного образования"}, {"number": 4, "title": "Педагогическая деятельность по реализации программ дошкольного образования"}, {"number": 5, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 6, "title": "Планирование образовательной деятельности в условиях реализации основной образовательной программы дошкольного образования"}, {"number": 7, "title": "Организация развивающей предметно-пространственной среды и психолого-педагогические условия"}, {"number": 8, "title": "Планирование и реализация музыкального образования в дошкольной образовательной организации в условиях реализации ФГОС дошкольного образования Итоговая аттестация"}, {"number": 9, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа в детском саду: музыкальный руководитель организует и проводит занятия по ФГОС ДО, направленные на развитие музыкального слуха, ритма, творческих способностей детей. В его задачи входит обучение песням, музыкально-ритмическим движениям, использование музыкальных игр, подготовка утренников, праздников и концертов.\\n\\nРабота в частных центрах детского развития: вы сможете вести групповые занятия по музыкальному развитию и разрабатывать программы, направленные на раннее эстетическое развитие детей, проводить индивидуальные занатия по вокалу. Работа в этой сфере позволяет гибко подбирать методики и индивидуально подходить к каждому ребёнку, формируя у детей интерес к музыке в игровой и творческой форме.\\n\\nРабота в школах искусств (дошкольное отделение): вы будете готовить детей к поступлению в музыкальную школу — проводить занятия по развитию музыкального слуха, чувства ритма, знакомству с нотной грамотой, готовить воспитанников к конкурсам и фестивалям. Такая работа является важным этапом в выявлении музыкально одарённых детей и формировании у них устойчивой мотивации к занятиям музыкой."], "abilities": []}', NULL, 1, @start_order + 20);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагогика и методика физической культуры и спорта. Тренер-преподаватель', 'pedagogika-i-metodika-fizicheskoy-kultury-i-sporta-trener-prepodavatel', 'Программа позволит по-новому взглянуть на физкультурно-спортивное воспитание в образовательных учреждениях и учреждениях дополнительного образования.', NULL, 'Школа', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Нормативно-правовые основы деятельности в сфере физической культуры и спорта"}, {"number": 2, "title": "Педагогика и психология физической культуры"}, {"number": 3, "title": "Теория и методика физической культуры"}, {"number": 4, "title": "Физическое воспитание в системе образовательных учреждений"}, {"number": 5, "title": "Гигиенические основы физической культуры и спорта"}, {"number": 6, "title": "Основы адаптивной физической культуры"}, {"number": 7, "title": "Теория спорта"}, {"number": 8, "title": "Менеджмент и экономика физической культуры и спорта Итоговая аттестация"}, {"number": 9, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа тренером в ДЮСШ/СДЮШОР: вы будете обучать детей и подростков выбранному виду спорта, готовить к участию в соревнованиях различного уровня, отбирать перспективных спортсменов в сборные команды. В задачи входит составление тренировочных программ, контроль физической подготовки, работа над тактикой и техникой, а также воспитание дисциплины, командного духа и стремления к спортивным достижениям.\\n\\nРабота учителем физкультуры в школе: в этой роли вы будете проводить уроки согласно образовательным стандартам, развивать у школьников общую физическую подготовку, формировать устойчивый интерес к регулярным занятиям спортом. Также в ваши обязанности войдёт организация школьных спортивных мероприятий и соревнований, проведение внеклассных секций и мониторинг физической активности учащихся.\\n\\nРабота преподавателем физвоспитания в колледже/вузе: здесь вы сможете обучать студентов более углублённо, уделяя внимание теории и практике физической культуры, а также формированию навыков самоконтроля, самостоятельных тренировок и здорового образа жизни. Преподаватель может внедрять современные методики физического воспитания молодежи, организовывать спортивные мероприятия, готовить к сдаче нормативов ГТО.\\n\\nРабота персональным тренером (частная практика): вы сможете проводить индивидуальные занятия с детьми или взрослыми, составлять персональные программы тренировок с учётом целей и физического состояния клиента, контролировать результаты и мотивировать на достижение поставленных задач. Такая деятельность позволяет выстраивать гибкий график работы, развивать собственный стиль преподавания и консультировать клиентов по вопросам физической активности и здорового образа жизни."], "abilities": []}', NULL, 1, @start_order + 21);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Методика и содержание деятельности в сфере физической культуры. Физическая культура в дошкольных образовательных организациях в условиях реализации ФГОС', 'metodika-i-soderzhanie-deyatelnosti-v-sfere-fizicheskoy-kultury-fizicheskaya-kultura-v-doshkolnyh-obrazovatelnyh-organizatsiyah-v-usloviyah-realizatsii-fgos', 'Программа позволит по-новому взглянуть на физическую культуру в образовании, осознать безграничный потенциал и всю важность грамотной работы с детьми дошкольного возраста в этом направлении.', NULL, 'Дошкольное образование', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 23850, '[{"number": 1, "title": "Организация образовательного процесса"}, {"number": 2, "title": "Нормативно-правовые основы деятельности в сфере физической культуры и спорта"}, {"number": 3, "title": "Психолого-педагогические основы дошкольного образования"}, {"number": 4, "title": "Теория и методика физической культуры"}, {"number": 5, "title": "Анатомия и физиология детей раннего и дошкольного возраста"}, {"number": 6, "title": "Здоровьесберегающие технологии в ДО. Основы медицинских знаний и здорового образа жизни"}, {"number": 7, "title": "Образовательный процесс по физической культуре в ДОУ"}, {"number": 8, "title": "Моделирование образовательного процесса по физической культуре в ДОУ на основе ФГОС Итоговая аттестация"}, {"number": 9, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа инструктором по физической культуре в детском саду: вы будете проводить занятия по развитию двигательной активности и координации у дошкольников, формировать у детей основы правильной осанки, прививать навыки здорового образа жизни. В ваши обязанности войдёт организация подвижных игр, спортивных праздников и утренней гимнастики, работа по профилактике нарушений физического развития, а также сотрудничество с воспитателями и родителями для укрепления здоровья детей.\\n\\nРабота тренером в детской спортивной школе или секции: здесь вы сможете развивать у дошкольников базовые спортивные навыки, готовить их к участию в соревнованиях и спортивных мероприятиях, формировать дисциплину, выносливость и командный дух. Ваша деятельность будет включать разработку тренировочных программ, подбор упражнений с учётом возраста и физической подготовки, а также воспитание интереса к регулярным занятиям спортом и достижению спортивных целей."], "abilities": []}', NULL, 1, @start_order + 22);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Дошкольная педагогика и психология. Психолого-педагогическая деятельность младшего воспитателя ДОУ в условиях реализации ФГОС', 'doshkolnaya-pedagogika-i-psihologiya-psihologo-pedagogicheskaya-deyatelnost-mladshego-vospitatelya-dou-v-usloviyah-realizatsii-fgos', 'Программа переподготовки для тех, кто желает профессионально выполнять свои должностные обязанности, связанные с организацией деятельности помощника воспитателя в рамках реализации ФГОС ДО.', NULL, 'Дошкольное образование', 280, 'pp', 'заочная с применением дистанционных образовательных технологий', 10350, '[{"number": 1, "title": "Федеральный государственный образовательный стандарт дошкольного образования"}, {"number": 2, "title": "Основы дошкольной педагогики"}, {"number": 3, "title": "Планируемые результаты дошкольного образования"}, {"number": 4, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 5, "title": "Уход и присмотр помощника воспитателя за детьми младенческого, раннего, дошкольного (от 3-х лет) возрастов и за детьми дошкольного возраста с ОВЗ и детьми-инвалидами Итоговая аттестация"}, {"number": 6, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": [], "abilities": []}', NULL, 1, @start_order + 23);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Деятельность старшего воспитателя в условиях реализации федерального государственного образовательного стандарта дошкольного образования', 'deyatelnost-starshego-vospitatelya-v-usloviyah-realizatsii-federalnogo-gosudarstvennogo-obrazovatelnogo-standarta-doshkolnogo-obrazovaniya', 'Программа позволит организовать методическое и организационное сопровождение образовательного процесса в дошкольных образовательных организациях.', NULL, 'Дошкольное образование', 520, 'pp', 'заочная с применением дистанционных образовательных технологий', 25050, '[{"number": 1, "title": "Федеральный государственный образовательный стандарт дошкольного образования"}, {"number": 2, "title": "Основы дошкольной педагогики"}, {"number": 3, "title": "Планируемые результаты дошкольного образования"}, {"number": 4, "title": "Педагогическая деятельность по реализации программ дошкольного образования"}, {"number": 5, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 6, "title": "Планирование образовательной деятельности в условиях реализации основной образовательной программы дошкольного образования"}, {"number": 7, "title": "Организация развивающей предметно-пространственной среды и психолого-педагогические условия"}, {"number": 8, "title": "Современные образовательные технологии"}, {"number": 9, "title": "Особенности организации образовательной деятельности с детьми с ОВЗ в ДОО в соответствии с ФГОС ДО"}, {"number": 10, "title": "Методическая деятельность в образовательном учреждении – роль, значение, правовые основы"}, {"number": 11, "title": "Особенности организации работы методиста (старшего воспитателя) дошкольного образовательного учреждения Итоговая аттестация"}, {"number": 12, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа старшим воспитателем в государственном или частном детском саду: вы будете организовывать образовательный процесс в соответствии с ФГОС, координировать работу воспитателей, корректировать образовательные программы и контролировать их реализацию, проводить диагностические мероприятия и мониторинг развития детей, обеспечивать создание комфортной и развивающей среды.\\n\\nРабота методистом в детском саду или учебном центре: вы сможете разрабатывать и внедрять инновационные педагогические методики, проводить консультации, обучающие семинары и тренинги для педагогов, организовывать повышение квалификации педагогов, координировать их работу и помогать в планировании занятий и мероприятий."], "abilities": []}', NULL, 1, @start_order + 24);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Государственное и муниципальное управление', 'gosudarstvennoe-i-munitsipalnoe-upravlenie', 'Программа готовит профессионалов, способных обеспечить эффективную деятельность органов государственной власти и местного самоуправления.', NULL, 'Охрана труда', 340, 'pp', 'заочная с применением дистанционных образовательных технологий', 15700, '[{"number": 1, "title": "Основы государственного и муниципального управления"}, {"number": 2, "title": "Документационное обеспечение государственного и муниципального управления"}, {"number": 3, "title": "Управление персоналом. Психология управления"}, {"number": 4, "title": "Административный этикет и служебная репутация государственного и муниципального служащего"}, {"number": 5, "title": "Противодействие коррупции"}, {"number": 6, "title": "Управление государственными и муниципальными закупками Итоговая аттестация"}, {"number": 7, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа в администрации муниципального образования: вы будете разрабатывать и внедрять программы развития города или района, курировать работу учреждений в сферах от ЖКХ до образования и культуры, станете связующим звеном между властью, общественными организациями, бизнесом и жителями региона.\\n\\nВы сможете специализироваться на работе с обращениями граждан: принимать запросы от населения и помогать решать возникшие проблемы, организовывать взаимодействие между ведомствами и контролировать исполнение поступивших обращений. Эта профессия даёт возможность реально влиять на жизнь города и видеть результаты своей работы."], "abilities": []}', NULL, 1, @start_order + 25);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Практическая психология. Психологическое консультирование в сфере сексуальных отношений', 'prakticheskaya-psihologiya-psihologicheskoe-konsultirovanie-v-sfere-seksualnyh-otnosheniy', 'Курс для тех, кто желает работать психологом-консультантом в области сексуальных отношений, уметь решать запросы связанные с супружескими отношениями, вопросами полового воспитания, вопросами принятия себя и своего тела, сексуальными травмами, сексуальными дисфункциями.', NULL, 'Психология', 1180, 'pp', 'заочная с применением дистанционных образовательных технологий', 55000, '[{"number": 1, "title": "Общая психология"}, {"number": 2, "title": "Психология личности"}, {"number": 3, "title": "Возрастная психология"}, {"number": 4, "title": "Основы психодиагностики"}, {"number": 5, "title": "Психология семьи"}, {"number": 6, "title": "Семейное консультирование"}, {"number": 7, "title": "Современные подходы психологического консультирования"}, {"number": 8, "title": "Кризисная психология"}, {"number": 9, "title": "Психотерапия посттравматических стрессовых расстройств"}, {"number": 10, "title": "Основы физиологии и анатомии"}, {"number": 11, "title": "Введение в сексологию"}, {"number": 12, "title": "Психофизиология сексуальности"}, {"number": 13, "title": "Сексуальное здоровье и понятие нормы в сексологии"}, {"number": 14, "title": "Сексуальные комплексы и психологическое обследование при сексуальных дисфункциях"}, {"number": 15, "title": "Родительская программа полового воспитания и развития детей и подростков"}, {"number": 16, "title": "Сексуальные сценарии"}, {"number": 17, "title": "Сексуальные отношения в семье"}, {"number": 18, "title": "Диагностика и терапия психосексуальных проблем в паре"}, {"number": 19, "title": "Психологическая работа с парой по проблемам репродуктивного выбора"}, {"number": 20, "title": "Сексуальная рутина"}, {"number": 21, "title": "Сексуальные расстройства и дисфункции. Сексуальные травмы"}, {"number": 22, "title": "Психологическая помощь в случае навязчивого маструбаторного поведения (у детей и взрослых) Итоговая аттестация"}, {"number": 23, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Ведение частной практики очно или онлайн: вы сможете консультировать индивидуально и работать с парами, разрабатывать и реализовывать персональные программы коррекции сексуального поведения, помогая преодолевать трудности в интимной сфере, повышать уровень доверия и гармонии в отношениях. Онлайн-формат открывает возможность расширить аудиторию и вести практику без привязки к конкретному месту.\\n\\nРабота в медицинских центрах (в паре с врачом-сексологом): вы будете проводить комплексную диагностику психогенных причин сексуальных расстройств, консультировать пары, сталкивающиеся с репродуктивными трудностями, а также оказывать психологическую поддержку в процессе реабилитации после сексуальных травм или хирургических вмешательств.\\n\\nПросветительская деятельность: психолог-консультант может вести блог, участвовать в подкастах, проводить лекции, семинары, курсы и вебинары, посвящённые вопросам сексуального здоровья, культуры отношений и психологии интимности. Такая работа помогает формировать ответственное и осознанное отношение к личной жизни, разрушать стереотипы и повышать уровень сексуальной грамотности общества."], "abilities": []}', NULL, 1, @start_order + 26);
INSERT IGNORE INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('Педагог предшкольной подготовки', 'pedagog-predshkolnoy-podgotovki', 'Для тех, кто хочет профессионально готовить детей 5–7 лет к школе, осваивая современные нейропедагогические и инклюзивные методики, цифровые форматы и требования ФГОС ДО для получения официальной квалификации «Педагог предшкольной подготовки».', 'Воспитатель\nОсвоите современные методики подготовки детей 5–7 лет к школе: от диагностики школьной готовности и обучения грамоте до нейропедагогических технологий и работы с детьми с ОВЗ. Научитесь проектировать образовательный процесс в соответствии с ФГОС ДО и ФОП ДО, выстраивать преемственность с начальной школой и эффективно взаимодействовать с родителями. После обучения вы получите диплом о профессиональной переподготовке с присвоением квалификации «Педагог предшкольной подготовки», который подтвердит вашу экспертизу и откроет возможности для карьерного роста в государственных и частных образовательных организациях.\n\n\nПедагог дополнительного образования\nОсвоите специализированные методики работы с детьми 5–7 лет: от диагностики школьной готовности до нейропедагогических технологий и адаптивных подходов для детей с ОВЗ.\n\n\nУчитель начальных классов\nИзучите психолого-педагогические особенности дошкольников, структуру готовности к школе и методики преемственности между детским садом и школой. Научитесь проводить входную диагностику, корректировать образовательный маршрут и снижать риски дезадаптации первоклассников.\n\n\nРепетитор по подготовке к школе\nПолучите системную практико-ориентированную подготовку: от обучения грамоте и математике до организации онлайн-занятий и взаимодействия с родителями. Освоите инструменты диагностики, адаптивные методики для детей с особыми потребностями и нейроигры для развития исполнительных функций. После завершения курса вы получите официальный диплом, который легитимизирует вашу частную практику и повысит доверие клиентов.', 'Дошкольное образование', 340, 'pp', 'заочная с применением дистанционных образовательных технологий', 18150, '[{"number": 1, "title": "Нормативно-правовые основы предшкольного образования"}, {"number": 2, "title": "Психолого-педагогические основы развития детей 5–7 лет"}, {"number": 3, "title": "Организация образовательного процесса"}, {"number": 4, "title": "Обучение грамоте, чтению и развитие речи"}, {"number": 5, "title": "Математика и логическое мышление"}, {"number": 6, "title": "Познавательное развитие и окружающий мир"}, {"number": 7, "title": "Социально-эмоциональное и физическое развитие"}, {"number": 8, "title": "Дети с миграционной историей и русский как неродной (РКН)"}, {"number": 9, "title": "Работа с детьми с ОВЗ в предшкольной подготовке"}, {"number": 10, "title": "Нейроподход: нейроигры и развитие исполнительных функций"}, {"number": 11, "title": "Методика групповых занятий"}, {"number": 12, "title": "Индивидуальные занятия и репетиторство"}, {"number": 13, "title": "Онлайн-занятия по подготовке к школе"}, {"number": 14, "title": "Взаимодействие с семьей и преемственность ДОО–школа Итоговая аттестация"}, {"number": 15, "title": "Итоговая аттестация"}]', '{"knowledge": [], "skills": ["Работа педагогом предшкольной подготовки в государственных и частных образовательных организациях, центрах развития детей: вы сможете проектировать и проводить занятия по подготовке детей 5–7 лет к школе, диагностировать школьную готовность, обучать грамоте и математике с применением нейропедагогических и инклюзивных методик, адаптировать программы для детей с ОВЗ и миграционной историей, а также обеспечивать преемственность между детским садом и начальной школой.\\n\\nРабота репетитором или частным специалистом по подготовке к школе: вы сможете вести индивидуальные и мини-групповые занятия в очном и онлайн-форматах, разрабатывать персональные образовательные маршруты, использовать цифровые ресурсы и нейроигры для развития исполнительных функций, а также консультировать родителей по вопросам школьной адаптации и поддержки ребёнка в период перехода к новому этапу обучения."], "abilities": []}', NULL, 1, @start_order + 27);
